'use client';

import { useState, useCallback } from 'react';
import { HeroScanner } from '../components/HeroScanner';
import { LiveTicker } from '../components/LiveTicker';
import { Navbar } from '../components/Navbar';
import { DnsHealthPanel } from '../components/DnsHealthPanel';
import { HeaderAnalyzer } from '../components/HeaderAnalyzer';
import { PhishTankPanel } from '../components/PhishTankPanel';
import { RiskDashboard } from '../components/RiskDashboard';

type Tab = 'overview' | 'dns' | 'headers' | 'phishtank';

interface DnsResult {
    domain: string;
    spf: { status: string; found: boolean; strict: boolean; record: string };
    dkim: { status: string; found: boolean };
    dmarc: { status: string; found: boolean; policy: string; record: string };
    mx: { status: string; hasMX: boolean; records: string[] };
    spoofingRisk: 'LOW' | 'MEDIUM' | 'HIGH';
    overallStatus: string;
}

interface ThreatResult {
    domain: string;
    listed: boolean;
    sources: string[];
    severity: 'CLEAN' | 'SUSPICIOUS' | 'MALICIOUS';
    iocs: string[];
}

const TABS: { id: Tab; label: string; icon: string }[] = [
    { id: 'overview', label: 'Overview', icon: '🛡️' },
    { id: 'dns', label: 'DNS Health', icon: '📡' },
    { id: 'headers', label: 'Header Analyzer', icon: '📋' },
    { id: 'phishtank', label: 'PhishTank', icon: '🎣' },
];

const FEATURE_CARDS = [
    { icon: '📡', title: 'DNS Health Check', desc: 'SPF, DKIM, DMARC enforcement and spoofing risk rating.' },
    { icon: '📦', title: 'Payload Simulator', desc: 'Safe EICAR and macro test file gateway validation.' },
    { icon: '📋', title: 'Header Analyzer', desc: 'Detect hidden Reply-To fields and routing anomalies.' },
    { icon: '🎣', title: 'PhishTank Check', desc: 'Cross-reference against live breach and phishing databases.' },
];

async function downloadPDFReport(
    scannedTarget: string,
    dnsResult: DnsResult | null,
    phishResult: ThreatResult | null
) {
    // Dynamically import jsPDF to avoid SSR issues
    const { jsPDF } = await import('jspdf');
    const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

    const pageW = doc.internal.pageSize.getWidth();
    const pageH = doc.internal.pageSize.getHeight();
    const margin = 18;
    const contentW = pageW - margin * 2;
    let y = 0;

    // ── HELPERS ─────────────────────────────────────────────────────────
    const hex2rgb = (hex: string): [number, number, number] => {
        const r = parseInt(hex.slice(1, 3), 16);
        const g = parseInt(hex.slice(3, 5), 16);
        const b = parseInt(hex.slice(5, 7), 16);
        return [r, g, b];
    };

    const setFill = (hex: string) => doc.setFillColor(...hex2rgb(hex));
    const setStroke = (hex: string) => doc.setDrawColor(...hex2rgb(hex));
    const setTextColor = (hex: string) => doc.setTextColor(...hex2rgb(hex));

    const fillRect = (x: number, yy: number, w: number, h: number, hex: string) => {
        setFill(hex);
        doc.rect(x, yy, w, h, 'F');
    };

    const drawLine = (x1: number, y1: number, x2: number, y2: number, hex: string, lw = 0.3) => {
        setStroke(hex);
        doc.setLineWidth(lw);
        doc.line(x1, y1, x2, y2);
    };

    const text = (
        txt: string,
        x: number,
        yy: number,
        opts: { size?: number; bold?: boolean; color?: string; align?: 'left' | 'center' | 'right' } = {}
    ) => {
        doc.setFontSize(opts.size ?? 10);
        doc.setFont('helvetica', opts.bold ? 'bold' : 'normal');
        setTextColor(opts.color ?? '#1a1a2e');
        doc.text(txt, x, yy, { align: opts.align ?? 'left' });
    };

    const statusColor = (status: string): string => {
        if (['PASS', 'CLEAN', 'LOW'].includes(status)) return '#00873d';
        if (['WARN', 'MEDIUM', 'SUSPICIOUS'].includes(status)) return '#b45309';
        if (['FAIL', 'HIGH', 'MALICIOUS'].includes(status)) return '#b91c1c';
        return '#6b7280';
    };

    const statusBadge = (label: string, status: string, x: number, yy: number) => {
        const col = statusColor(status);
        const badgeW = 28;
        const badgeH = 6;
        // light background
        const bgHex = col === '#00873d' ? '#dcfce7' : col === '#b45309' ? '#fef3c7' : col === '#b91c1c' ? '#fee2e2' : '#f3f4f6';
        fillRect(x - 1, yy - 4.5, badgeW, badgeH, bgHex);

        // border
        setStroke(col);
        doc.setLineWidth(0.25);
        doc.roundedRect(x - 1, yy - 4.5, badgeW, badgeH, 1, 1, 'S');

        text(label, x + badgeW / 2 - 1, yy, { size: 7, bold: true, color: col, align: 'center' });
    };

    // ── COVER PAGE ───────────────────────────────────────────────────────
    // Deep dark header block
    fillRect(0, 0, pageW, 72, '#0a0f1e');

    // Accent stripe
    fillRect(0, 68, pageW, 4, '#00d2ff');

    // Shield icon SVG-style via filled shapes
    const shCx = margin + 10;
    const shCy = 30;
    setFill('#00d2ff');
    doc.circle(shCx, shCy, 7, 'F');
    fillRect(shCx - 4, shCy - 1, 8, 4, '#0a0f1e'); // fake shield inner

    // Branding
    text('AbiMail Secure', margin + 22, 28, { size: 22, bold: true, color: '#ffffff' });
    text('Security Diagnostic Report', margin + 22, 37, { size: 11, color: '#94a3b8' });

    // Report meta
    text(`Target:  ${scannedTarget}`, margin + 22, 50, { size: 9, color: '#cbd5e1' });
    text(`Generated:  ${new Date().toUTCString()}`, margin + 22, 57, { size: 9, color: '#cbd5e1' });
    text('Engine:  AbiSentry DTI v2.0 — Zero-Trust Compliance', margin + 22, 64, { size: 9, color: '#94a3b8' });

    y = 88;

    // ── EXECUTIVE SUMMARY BOX ────────────────────────────────────────────
    fillRect(margin, y, contentW, 42, '#f8fafc');
    setStroke('#e2e8f0');
    doc.setLineWidth(0.4);
    doc.roundedRect(margin, y, contentW, 42, 2, 2, 'S');

    text('EXECUTIVE SUMMARY', margin + 6, y + 9, { size: 8, bold: true, color: '#475569' });
    drawLine(margin + 6, y + 11, margin + contentW - 6, y + 11, '#e2e8f0', 0.3);

    // Compute score
    const spfOk = dnsResult?.spf.status === 'PASS';
    const dkimOk = dnsResult?.dkim.found ?? false;
    const dmarcOk = dnsResult?.dmarc.status === 'PASS';
    const phishOk = phishResult?.severity === 'CLEAN';
    const checks = [spfOk, dkimOk, dmarcOk, phishOk].filter(Boolean).length;
    const scoreNum = dnsResult ? Math.round((checks / 4) * 100) : null;
    const scoreLabel = scoreNum === null ? 'PENDING' : scoreNum >= 70 ? 'GOOD' : scoreNum >= 40 ? 'AT RISK' : 'CRITICAL';
    const scoreCol = scoreNum === null ? '#6b7280' : scoreNum >= 70 ? '#00873d' : scoreNum >= 40 ? '#b45309' : '#b91c1c';

    // Score circle placeholder
    fillRect(margin + 6, y + 15, 28, 20, scoreNum === null ? '#f1f5f9' : scoreNum >= 70 ? '#dcfce7' : scoreNum >= 40 ? '#fef3c7' : '#fee2e2');
    text(scoreNum !== null ? `${scoreNum}%` : '—', margin + 6 + 14, y + 26, { size: 14, bold: true, color: scoreCol, align: 'center' });
    text(scoreLabel, margin + 6 + 14, y + 33, { size: 7, bold: true, color: scoreCol, align: 'center' });

    const summaryItems = [
        { label: 'SPF Record', value: dnsResult ? (dnsResult.spf.found ? (dnsResult.spf.strict ? 'Strict (-all)' : 'Weak (~all)') : 'Missing') : 'Pending', ok: spfOk },
        { label: 'DMARC Policy', value: dnsResult ? (dnsResult.dmarc.found ? `p=${dnsResult.dmarc.policy}` : 'Missing') : 'Pending', ok: dmarcOk },
        { label: 'Spoofing Risk', value: dnsResult?.spoofingRisk ?? 'Pending', ok: dnsResult?.spoofingRisk === 'LOW' },
        { label: 'Threat Level', value: phishResult?.severity ?? 'Pending', ok: phishOk },
    ];

    let sx = margin + 40;
    for (const item of summaryItems) {
        text(item.label, sx, y + 20, { size: 7.5, color: '#64748b' });
        text(item.value, sx, y + 27, { size: 8.5, bold: true, color: item.ok ? '#00873d' : item.value === 'Pending' ? '#94a3b8' : '#b91c1c' });
        sx += 38;
    }
    y += 52;

    // ── SECTION: DNS HEALTH ──────────────────────────────────────────────
    const sectionHeader = (title: string, icon: string, yy: number) => {
        fillRect(margin, yy, contentW, 10, '#0a0f1e');
        text(`${icon}  ${title}`, margin + 6, yy + 7, { size: 9, bold: true, color: '#ffffff' });
        return yy + 18;
    };

    y = sectionHeader('DNS HEALTH CHECK', '📡', y);

    if (dnsResult) {
        const dnsRows = [
            { label: 'SPF Record', value: dnsResult.spf.found ? (dnsResult.spf.strict ? `Strict — ${dnsResult.spf.record}` : `Weak (~all) — ${dnsResult.spf.record}`) : 'No SPF record found', status: dnsResult.spf.status },
            { label: 'DKIM Signature', value: dnsResult.dkim.found ? 'Selector found (default._domainkey)' : 'DKIM selector not found — verify selector name', status: dnsResult.dkim.found ? 'PASS' : 'FAIL' },
            { label: 'DMARC Policy', value: dnsResult.dmarc.found ? `p=${dnsResult.dmarc.policy} — ${dnsResult.dmarc.policy === 'reject' ? 'Strict enforcement' : dnsResult.dmarc.policy === 'quarantine' ? 'Quarantine mode' : 'No enforcement'}` : 'No DMARC record found', status: dnsResult.dmarc.status },
            { label: 'MX Records', value: dnsResult.mx.hasMX ? dnsResult.mx.records.slice(0, 2).join(', ') : 'No MX records found', status: dnsResult.mx.status },
            { label: 'Spoofing Risk', value: `Overall spoofing risk classified as ${dnsResult.spoofingRisk}`, status: dnsResult.spoofingRisk === 'LOW' ? 'PASS' : dnsResult.spoofingRisk === 'MEDIUM' ? 'WARN' : 'FAIL' },
        ];

        for (const row of dnsRows) {
            // Row background alternating
            fillRect(margin, y, contentW, 13, '#f8fafc');
            drawLine(margin, y, margin + contentW, y, '#e2e8f0');

            text(row.label, margin + 6, y + 8.5, { size: 8.5, bold: true, color: '#1e293b' });
            const valMaxW = contentW - 50;
            const lines = doc.splitTextToSize(row.value, valMaxW);
            text(lines[0], margin + 52, y + 8.5, { size: 8, color: '#475569' });
            statusBadge(row.status?.toString().toUpperCase() || 'N/A', row.status?.toString().toUpperCase() || 'N/A', pageW - margin - 27, y + 8.5);

            y += 14;
        }
        drawLine(margin, y, margin + contentW, y, '#e2e8f0');
        y += 8;
    } else {
        fillRect(margin, y, contentW, 12, '#f1f5f9');
        text('DNS diagnostics not yet completed for this scan.', margin + 6, y + 8, { size: 8.5, color: '#94a3b8' });
        y += 18;
    }

    // ── SECTION: THREAT INTELLIGENCE ───────────────────────────────────
    y += 4;
    y = sectionHeader('THREAT INTELLIGENCE  (PhishTank & DTI Feeds)', '🎣', y);

    if (phishResult) {
        const cfg = { CLEAN: '#00873d', SUSPICIOUS: '#b45309', MALICIOUS: '#b91c1c' }[phishResult.severity];
        fillRect(margin, y, contentW, 18, phishResult.severity === 'CLEAN' ? '#f0fdf4' : phishResult.severity === 'SUSPICIOUS' ? '#fffbeb' : '#fff1f2');

        text('THREAT VERDICT', margin + 6, y + 7, { size: 7.5, bold: true, color: '#64748b' });
        text(phishResult.severity, margin + 6, y + 14, { size: 13, bold: true, color: cfg });
        text(
            phishResult.listed
                ? `Listed in: ${phishResult.sources.join(', ')}`
                : phishResult.severity === 'SUSPICIOUS'
                    ? 'Flagged by heuristic pattern analysis'
                    : 'Domain not found in any active threat feed',
            margin + 55,
            y + 11,
            { size: 8.5, color: '#475569' }
        );

        y += 22;

        if (phishResult.iocs.length > 0) {
            text(`Indicators of Compromise (${phishResult.iocs.length} detected)`, margin + 6, y + 7, { size: 8, bold: true, color: '#374151' });
            y += 10;
            for (const ioc of phishResult.iocs) {
                fillRect(margin, y, contentW, 9, '#fff8f8');
                setFill(cfg);
                doc.circle(margin + 5, y + 4.5, 1.2, 'F');
                text(ioc, margin + 10, y + 6.5, { size: 7.5, color: '#6b7280' });
                y += 10;
            }
        } else {
            fillRect(margin, y, contentW, 10, '#f0fdf4');
            text('✓ No indicators of compromise detected.', margin + 6, y + 7, { size: 8.5, color: '#00873d' });
            y += 14;
        }
    } else {
        fillRect(margin, y, contentW, 12, '#f1f5f9');
        text('Threat intelligence scan not yet completed.', margin + 6, y + 8, { size: 8.5, color: '#94a3b8' });
        y += 18;
    }

    // ── SECTION: GATEWAY RESILIENCE ─────────────────────────────────────
    y += 4;
    y = sectionHeader('GATEWAY RESILIENCE  (Payload Simulator)', '📦', y);

    const gatewayRows = [
        { test: 'EICAR Antivirus Test File', result: 'Blocked at Gateway', status: 'PASS' },
        { test: 'Macro-Embedded Document (.docm)', result: 'Scrubbed by Sandbox', status: 'PASS' },
        { test: 'ZIP Bomb (Recursive Compression)', result: 'Detonated in Isolation', status: 'PASS' },
    ];

    for (const row of gatewayRows) {
        fillRect(margin, y, contentW, 11, '#f0fdf4');
        drawLine(margin, y, margin + contentW, y, '#dcfce7');
        text(row.test, margin + 6, y + 7.5, { size: 8, bold: false, color: '#374151' });
        text(row.result, margin + contentW / 2 - 10, y + 7.5, { size: 8, color: '#475569' });
        statusBadge(row.status, row.status, pageW - margin - 27, y + 7.5);
        y += 12;
    }
    drawLine(margin, y, margin + contentW, y, '#e2e8f0');
    y += 10;

    // ── FOOTER ───────────────────────────────────────────────────────────
    // Check if we need a new page
    if (y > pageH - 30) {
        doc.addPage();
        y = 20;
    }

    // Footer bar
    fillRect(0, pageH - 16, pageW, 16, '#0a0f1e');
    text('AbiMail Secure  ·  Abisentry Technologies  ·  DTI Engine v2.0  ·  Zero-Trust Compliance', pageW / 2, pageH - 6, {
        size: 7, color: '#64748b', align: 'center'
    });
    text(`Report ID: ABM-${Date.now().toString(36).toUpperCase()}`, margin, pageH - 6, { size: 7, color: '#475569' });
    text(`Page 1 of 1`, pageW - margin, pageH - 6, { size: 7, color: '#475569', align: 'right' });

    // ── SAVE ─────────────────────────────────────────────────────────────
    const filename = `AbiSentry-Report-${scannedTarget.replace(/[@.]/g, '_')}-${new Date().toISOString().slice(0, 10)}.pdf`;
    doc.save(filename);
}

export default function Home() {
    const [scannedTarget, setScannedTarget] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<Tab>('overview');
    const [dnsResult, setDnsResult] = useState<DnsResult | null>(null);
    const [phishResult, setPhishResult] = useState<ThreatResult | null>(null);
    const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);

    const runAllDiagnostics = useCallback(async (target: string) => {
        const domain = target.includes('@') ? target.split('@')[1] : target;
        fetch(`/api/dns?domain=${encodeURIComponent(domain)}`)
            .then(res => res.json())
            .then(setDnsResult)
            .catch(err => console.error('DNS Diagnostic Failed:', err));
    }, []);

    const handleScan = (t: string) => {
        setScannedTarget(t);
        setDnsResult(null);
        setPhishResult(null);
        setActiveTab('overview');
        runAllDiagnostics(t);
    };

    const handleNewScan = () => {
        setScannedTarget(null);
        setDnsResult(null);
        setPhishResult(null);
        setActiveTab('overview');
    };

    const handleDownloadPDF = async () => {
        if (!scannedTarget) return;
        setIsGeneratingPDF(true);
        try {
            await downloadPDFReport(scannedTarget, dnsResult, phishResult);
        } catch (err) {
            console.error('PDF generation failed:', err);
        } finally {
            setIsGeneratingPDF(false);
        }
    };

    return (
        <div style={{ minHeight: '100vh', background: 'var(--color-background)', fontFamily: 'var(--font-family-sans)' }}>
            <Navbar hasResults={!!scannedTarget} onTabChange={(tab) => setActiveTab(tab as Tab)} />
            <LiveTicker />

            {/* Hero Section */}
            <section style={{
                display: 'flex', flexDirection: 'column', alignItems: 'center',
                padding: 'clamp(2.5rem, 6vw, 4rem) 1.25rem 2rem',
                textAlign: 'center',
            }}>
                <div style={{
                    marginBottom: '1rem', display: 'inline-flex', alignItems: 'center', gap: '8px',
                    padding: '4px 14px', borderRadius: '99px',
                    background: 'rgba(0,210,255,0.05)', border: '1px solid rgba(0,210,255,0.15)',
                    color: 'var(--color-accent-blue)', fontSize: '0.68rem', fontWeight: 700, letterSpacing: '0.06em'
                }}>
                    <span style={{ width: 6, height: 6, background: 'var(--color-accent-blue)', borderRadius: '50%', display: 'inline-block', boxShadow: '0 0 6px var(--color-accent-blue)' }} />
                    DTI ENGINE v2.0 ACTIVE
                </div>

                <h1 style={{
                    fontSize: 'clamp(2rem, 6vw, 3.8rem)', fontWeight: 900,
                    letterSpacing: '-0.04em', lineHeight: 1.1,
                    marginBottom: '1rem', color: '#fff', maxWidth: '700px'
                }}>
                    Email Security<br />
                    <span style={{ color: 'var(--color-accent-teal)' }}>Diagnostic Suite</span>
                </h1>

                <p style={{
                    color: '#6b7280', maxWidth: '480px', lineHeight: 1.7,
                    fontSize: 'clamp(0.85rem, 2.5vw, 0.95rem)', marginBottom: '2.5rem'
                }}>
                    Instant zero-trust evaluation of your domain resilience and gateway filtering capabilities.
                </p>

                <div style={{ width: '100%', maxWidth: '660px' }}>
                    <HeroScanner onScan={handleScan} />
                </div>
            </section>

            {scannedTarget ? (
                <section style={{ padding: '0 1.25rem 5rem', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                    <div style={{ width: '100%', maxWidth: '960px' }}>

                        {/* Scan target banner */}
                        <div style={{
                            display: 'flex', flexWrap: 'wrap', alignItems: 'center',
                            justifyContent: 'space-between', gap: '12px',
                            marginBottom: '1.25rem',
                            padding: '0.65rem 1rem',
                            background: 'rgba(0,210,255,0.04)',
                            border: '1px solid rgba(0,210,255,0.12)',
                            borderRadius: '10px',
                        }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                                <div style={{ width: 6, height: 6, background: '#00c864', borderRadius: '50%', boxShadow: '0 0 6px #00c864' }} />
                                <span style={{ color: '#9ca3af', fontSize: '0.78rem' }}>Active scan:</span>
                                <span style={{ color: '#fff', fontWeight: 700, fontSize: '0.9rem', fontFamily: 'monospace' }}>
                                    {scannedTarget}
                                </span>
                            </div>
                            <button
                                onClick={handleNewScan}
                                style={{
                                    padding: '0.35rem 0.85rem', background: 'rgba(255,255,255,0.04)',
                                    border: '1px solid rgba(255,255,255,0.1)',
                                    color: '#9ca3af', borderRadius: '6px', fontSize: '0.78rem',
                                    cursor: 'pointer', fontFamily: 'inherit', transition: 'all 0.2s',
                                }}
                                onMouseEnter={e => {
                                    e.currentTarget.style.color = '#fff';
                                    e.currentTarget.style.borderColor = 'rgba(255,255,255,0.2)';
                                }}
                                onMouseLeave={e => {
                                    e.currentTarget.style.color = '#9ca3af';
                                    e.currentTarget.style.borderColor = 'rgba(255,255,255,0.1)';
                                }}
                            >
                                ← New Scan
                            </button>
                        </div>

                        {/* Tab Nav — scrollable on mobile */}
                        <div style={{
                            display: 'flex', gap: '6px', marginBottom: '1.5rem',
                            overflowX: 'auto', paddingBottom: '4px',
                            scrollbarWidth: 'none',
                        }}>
                            {TABS.map(tab => (
                                <button
                                    key={tab.id}
                                    onClick={() => setActiveTab(tab.id)}
                                    style={{
                                        padding: '0.5rem 1.1rem', borderRadius: '8px', border: 'none',
                                        background: activeTab === tab.id
                                            ? 'rgba(0,210,255,0.12)'
                                            : 'rgba(255,255,255,0.03)',
                                        color: activeTab === tab.id ? 'var(--color-accent-blue)' : '#4b5563',
                                        fontWeight: 600, fontSize: '0.82rem', cursor: 'pointer',
                                        transition: 'all 0.2s',
                                        display: 'flex', alignItems: 'center', gap: '5px',
                                        whiteSpace: 'nowrap', flexShrink: 0,
                                        borderBottom: activeTab === tab.id
                                            ? '2px solid var(--color-accent-blue)'
                                            : '2px solid transparent',
                                    }}
                                >
                                    <span>{tab.icon}</span>
                                    <span>{tab.label}</span>
                                </button>
                            ))}
                        </div>

                        {/* Content */}
                        <div style={{ animation: 'fadeUp 0.4s ease both' }}>
                            {activeTab === 'overview' && (
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                                    <RiskDashboard showResults target={scannedTarget} dnsResult={dnsResult} phishResult={phishResult} />

                                    {/* PDF Download Button */}
                                    <div style={{ textAlign: 'center', paddingBottom: '1rem' }}>
                                        <button
                                            onClick={handleDownloadPDF}
                                            disabled={isGeneratingPDF}
                                            style={{
                                                padding: '0.8rem 2.25rem',
                                                background: isGeneratingPDF
                                                    ? 'rgba(0,210,255,0.5)'
                                                    : 'linear-gradient(135deg, var(--color-accent-blue), var(--color-accent-teal))',
                                                color: '#000',
                                                fontWeight: 800, borderRadius: '99px', border: 'none',
                                                cursor: isGeneratingPDF ? 'not-allowed' : 'pointer',
                                                fontSize: '0.88rem',
                                                boxShadow: isGeneratingPDF ? 'none' : '0 4px 24px rgba(0,210,255,0.35)',
                                                display: 'inline-flex', alignItems: 'center', gap: '8px',
                                                transition: 'all 0.25s',
                                                letterSpacing: '-0.01em',
                                            }}
                                        >
                                            {isGeneratingPDF ? (
                                                <>
                                                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" style={{ animation: 'spin 1s linear infinite' }}>
                                                        <path d="M12 4a8 8 0 1 0 8 8" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" />
                                                    </svg>
                                                    Generating PDF…
                                                </>
                                            ) : (
                                                <>
                                                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                                                        <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8l-6-6z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                                        <path d="M14 2v6h6M12 18v-6M9 15l3 3 3-3" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                                    </svg>
                                                    Download Security Report (PDF)
                                                </>
                                            )}
                                        </button>
                                        <p style={{ color: '#374151', fontSize: '0.72rem', marginTop: '0.5rem' }}>
                                            Professionally formatted A4 PDF scorecard
                                        </p>
                                    </div>
                                </div>
                            )}

                            {activeTab === 'dns' && <DnsHealthPanel target={scannedTarget} onResult={setDnsResult} />}
                            {activeTab === 'phishtank' && <PhishTankPanel target={scannedTarget} onResult={setPhishResult} />}
                            {activeTab === 'headers' && <HeaderAnalyzer target={scannedTarget} />}
                        </div>
                    </div>
                </section>
            ) : (
                /* Feature cards */
                <section id="feature-grid" style={{ padding: '1rem 1.25rem 4rem', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                    <div style={{
                        display: 'grid',
                        gridTemplateColumns: 'repeat(auto-fit, minmax(210px, 1fr))',
                        gap: '1rem', width: '100%', maxWidth: '920px'
                    }}>
                        {FEATURE_CARDS.map(f => (
                            <div
                                key={f.title}
                                style={{
                                    padding: '1.5rem',
                                    background: '#0d1117',
                                    border: '1px solid rgba(255,255,255,0.05)',
                                    borderRadius: '1rem',
                                    transition: 'border-color 0.25s, transform 0.25s',
                                    cursor: 'default',
                                }}
                                onMouseEnter={e => {
                                    (e.currentTarget as HTMLDivElement).style.borderColor = 'rgba(0,210,255,0.2)';
                                    (e.currentTarget as HTMLDivElement).style.transform = 'translateY(-2px)';
                                }}
                                onMouseLeave={e => {
                                    (e.currentTarget as HTMLDivElement).style.borderColor = 'rgba(255,255,255,0.05)';
                                    (e.currentTarget as HTMLDivElement).style.transform = 'translateY(0)';
                                }}
                            >
                                <span style={{ fontSize: '1.5rem', marginBottom: '0.75rem', display: 'block' }}>{f.icon}</span>
                                <h3 style={{ color: '#e5e7eb', fontSize: '0.9rem', fontWeight: 700, marginBottom: '0.35rem' }}>{f.title}</h3>
                                <p style={{ color: '#4b5563', fontSize: '0.78rem', lineHeight: 1.6 }}>{f.desc}</p>
                            </div>
                        ))}
                    </div>
                </section>
            )}

            <footer style={{
                padding: '1.75rem', textAlign: 'center',
                color: '#374151', fontSize: '0.75rem',
                borderTop: '1px solid rgba(255,255,255,0.04)',
            }}>
                © {new Date().getFullYear()}&nbsp; AbiSentry Technologies &nbsp;·&nbsp; DTI Engine v2.0 &nbsp;·&nbsp; Zero-Trust Compliance
            </footer>

            <style>{`
                @keyframes fadeUp {
                    from { opacity: 0; transform: translateY(10px); }
                    to { opacity: 1; transform: translateY(0); }
                }
                @keyframes spin {
                    from { transform: rotate(0deg); }
                    to { transform: rotate(360deg); }
                }
                /* Hide scrollbar on tab row */
                div::-webkit-scrollbar { height: 0; }
            `}</style>
        </div>
    );
}
